  1→import React, { useState, useCallback, useImperativeHandle, forwardRef, useEffect, useRef } from "react";
  2→import { invoke } from "@tauri-apps/api/core";
  3→import { getCurrentWindow } from "@tauri-apps/api/window";
  4→import { GhosttyTerminal } from "./GhosttyTerminal";
  5→import { getPaneChrome } from "./chrome";
  6→import { formatDroppedImagePaths } from "./drop-paths";
  7→import {
  8→  clearPaneAutoLaunch,
  9→  closePaneInTerminalTab,
 10→  closeTerminalTabInWorkspace,
 11→  createTerminalTabInWorkspace,
 12→  resolveAutoLaunchTarget,
 13→  resolveAgentLaunchTarget,
 14→  setActivePaneInTerminalTab,
 15→  setActiveTerminalTabInWorkspace,
 16→  setPaneSession,
 17→  setSplitRatioInTerminalTab,
 18→  splitActivePaneInTerminalTab,
 19→  type TerminalTabState,
 20→  type TerminalWorkspace,
 21→  type WorkspaceUpdate,
 22→} from "./workspace";
 23→import type { Tab } from "../../App";
 24→
 25→function debugLog(msg: string) {
 26→  invoke("debug_log", { message: msg }).catch(() => {});
 27→}
 28→
 29→export interface TerminalPanelHandle {
 30→  launchSession: (options?: { agent?: string; prompt?: string }) => Promise<void>;
 31→}
 32→
 33→export interface TermSession {
 34→  id: string;
 35→  agent: string;
 36→  label: string;
 37→}
 38→
 39→function buildSessionLabel(branch: string, agent: string) {
 40→  if (agent === "claude-code") return `Claude - ${branch}`;
 41→  if (agent === "codex") return `Codex - ${branch}`;
 42→  return `Terminal - ${branch}`;
 43→}
 44→
 45→interface TerminalPanelProps {
 46→  height: number;
 47→  tab: Tab;
 48→  workspace: TerminalWorkspace;
 49→  onWorkspaceChange: (update: WorkspaceUpdate) => void;
 50→  onToggle: () => void;
 51→  dialogOpen?: boolean;
 52→}
 53→
 54→function getActiveTerminalTab(workspace: TerminalWorkspace): TerminalTabState | null {
 55→  return (
 56→    workspace.terminalTabs.find(
 57→      (terminalTab) => terminalTab.id === workspace.activeTerminalTabId
 58→    ) ??
 59→    workspace.terminalTabs[0] ??
 60→    null
 61→  );
 62→}
 63→
 64→export const TerminalPanel = forwardRef<TerminalPanelHandle, TerminalPanelProps>(
 65→  function TerminalPanel({ height, tab, workspace, onWorkspaceChange, onToggle, dialogOpen }, ref) {
 66→  const [isLaunching, setIsLaunching] = useState(false);
 67→  const [isDropTarget, setIsDropTarget] = useState(false);
 68→  const [error, setError] = useState<string | null>(null);
 69→  const panelRef = useRef<HTMLDivElement>(null);
 70→  const activeTerminalTab = getActiveTerminalTab(workspace);
 71→  const activePane =
 72→    activeTerminalTab?.panes.find((pane) => pane.id === activeTerminalTab.activePaneId) ??
 73→    activeTerminalTab?.panes[0] ??
 74→    null;
 75→  const activeSurfaceId = activePane?.session?.id ?? null;
 76→
 77→  const isPositionInsidePanel = useCallback((position: { x: number; y: number }) => {
 78→    const rect = panelRef.current?.getBoundingClientRect();
 79→    if (!rect) return false;
 80→
 81→    return (
 82→      position.x >= rect.left &&
 83→      position.x <= rect.right &&
 84→      position.y >= rect.top &&
 85→      position.y <= rect.bottom
 86→    );
 87→  }, []);
 88→
 89→  const sendDroppedImagePaths = useCallback(async (paths: string[]) => {
 90→    if (!activeSurfaceId) return;
 91→
 92→    const text = formatDroppedImagePaths(paths);
 93→    if (!text) return;
 94→
 95→    try {
 96→      await invoke("ghostty_send_text", {
 97→        surfaceId: activeSurfaceId,
 98→        text,
 99→      });
100→      await invoke("ghostty_focus_overlay", { surfaceId: activeSurfaceId });
101→    } catch (err) {
102→      console.error("Failed to send dropped paths to terminal:", err);
103→      setError("Could not insert dropped image path into the terminal");
104→    }
105→  }, [activeSurfaceId]);
106→
107→  const focusPane = useCallback(
108→    (terminalTabId: string, paneId: string) => {
109→      const nextWorkspace = setActivePaneInTerminalTab(
110→        setActiveTerminalTabInWorkspace(workspace, terminalTabId),
111→        terminalTabId,
112→        paneId
113→      );
114→      onWorkspaceChange(nextWorkspace);
115→      const pane = nextWorkspace.terminalTabs
116→        .find((terminalTab) => terminalTab.id === terminalTabId)
117→        ?.panes.find((candidate) => candidate.id === paneId);
118→      if (pane?.session) {
119→        invoke("ghostty_focus_overlay", { surfaceId: pane.session.id }).catch(
120→          console.error
121→        );
122→      }
123→    },
124→    [workspace, onWorkspaceChange]
125→  );
126→
127→  const launchTerminal = useCallback(
128→    async (
129→      agent = "terminal",
130→      target?: { terminalTabId?: string; paneId?: string }
131→    ) => {
132→      debugLog(`launchTerminal called: tab.id=${tab.id}, tab.repoPath=${JSON.stringify(tab.repoPath)}, tab.branch=${tab.branch}, isLaunching=${isLaunching}`);
133→
134→      if (!tab.repoPath) {
135→        debugLog("BAIL: tab.repoPath is empty/falsy");
136→        setError("No repository selected — pick a branch from the sidebar");
137→        return "";
138→      }
139→      if (isLaunching) {
140→        debugLog("BAIL: isLaunching=true, already in progress");
141→        return "";
142→      }
143→
144→      let nextWorkspace = workspace;
145→      let terminalTabId = target?.terminalTabId;
146→      let paneId = target?.paneId;
147→
148→      if (!terminalTabId || !paneId) {
149→        const launchTarget = resolveAgentLaunchTarget(nextWorkspace);
150→        if (launchTarget.mode === "create-terminal-tab") {
151→          nextWorkspace = createTerminalTabInWorkspace(nextWorkspace);
152→          const nextTarget = resolveAgentLaunchTarget(nextWorkspace);
153→          if (nextTarget.mode === "create-terminal-tab") {
154→            return "";
155→          }
156→          terminalTabId = nextTarget.terminalTabId;
157→          paneId = nextTarget.paneId;
158→        } else {
159→          terminalTabId = launchTarget.terminalTabId;
160→          paneId = launchTarget.paneId;
161→        }
162→      }
163→
164→      if (!terminalTabId || !paneId) {
165→        return "";
166→      }
167→
168→      nextWorkspace = setActivePaneInTerminalTab(
169→        setActiveTerminalTabInWorkspace(nextWorkspace, terminalTabId),
170→        terminalTabId,
171→        paneId
172→      );
173→      onWorkspaceChange(nextWorkspace);
174→
175→      const targetTab = nextWorkspace.terminalTabs.find(
176→        (terminalTab) => terminalTab.id === terminalTabId
177→      );
178→      const targetPane = targetTab?.panes.find((pane) => pane.id === paneId);
179→
180→      if (targetPane?.session) {
181→        debugLog(`Reusing existing session ${targetPane.session.id} for pane ${paneId}`);
182→        return targetPane.session.id;
183→      }
184→
185→      setError(null);
186→      setIsLaunching(true);
187→      debugLog(`Calling ghostty_create_surface with workingDir=${tab.repoPath}`);
188→      try {
189→        const surfaceId: string = await invoke("ghostty_create_surface", {
190→          workingDir: tab.repoPath,
191→          command: agent === "terminal" ? undefined : agent,
192→        });
193→
194→        debugLog(`ghostty_create_surface returned surfaceId=${surfaceId}`);
195→        const newSession: TermSession = {
196→          id: surfaceId,
197→          agent,
198→          label: buildSessionLabel(tab.branch, agent),
199→        };
200→        onWorkspaceChange((currentWorkspace) =>
201→          setPaneSession(currentWorkspace, terminalTabId, paneId, newSession)
202→        );
203→        return surfaceId;
204→      } catch (err) {
205→        const message = err instanceof Error ? err.message : String(err);
206→        debugLog(`ghostty_create_surface FAILED: ${message}`);
207→        console.error("Failed to create ghostty surface:", err);
208→        setError(`Terminal failed: ${message}`);
209→        return "";
210→      } finally {
211→        setIsLaunching(false);
212→      }
213→    },
214→    [tab.id, tab.repoPath, tab.branch, workspace, isLaunching, onWorkspaceChange]
215→  );
216→
217→  const killPaneSession = useCallback(async (terminalTabId: string, paneId: string) => {
218→    const terminalTab = workspace.terminalTabs.find(
219→      (candidate) => candidate.id === terminalTabId
220→    );
221→    const pane = terminalTab?.panes.find((candidate) => candidate.id === paneId);
222→    if (!pane?.session) return;
223→    try {
224→      await invoke("ghostty_destroy_surface", { surfaceId: pane.session.id });
225→    } catch (err) {
226→      console.error("Failed to destroy surface:", err);
227→    }
228→    onWorkspaceChange((currentWorkspace) =>
229→      setPaneSession(currentWorkspace, terminalTabId, paneId, null)
230→    );
231→  }, [workspace, onWorkspaceChange]);
232→
233→  const closeTerminalTab = useCallback(async (terminalTabId: string) => {
234→    const terminalTab = workspace.terminalTabs.find(
235→      (candidate) => candidate.id === terminalTabId
236→    );
237→    if (!terminalTab) return;
238→
239→    for (const pane of terminalTab.panes) {
240→      if (pane.session) {
241→        try {
242→          await invoke("ghostty_destroy_surface", { surfaceId: pane.session.id });
243→        } catch (err) {
244→          console.error("Failed to destroy surface:", err);
245→        }
246→      }
247→    }
248→
249→    onWorkspaceChange((currentWorkspace) =>
250→      closeTerminalTabInWorkspace(currentWorkspace, terminalTabId)
251→    );
252→  }, [workspace, onWorkspaceChange]);
253→
254→  useImperativeHandle(ref, () => ({
255→    async launchSession(options = {}) {
256→      const agent = options.agent ?? "terminal";
257→      const surfaceId = await launchTerminal(agent);
258→      if (!surfaceId) return;
259→      if (!options.prompt) return;
260→
261→      // Small delay for PTY initialization, then send the prompt
262→      setTimeout(async () => {
263→        try {
264→          await invoke("ghostty_send_text", {
265→            surfaceId,
266→            text: options.prompt + "\n",
267→          });
268→        } catch (err) {
269→          console.error("Failed to send prompt to terminal:", err);
270→        }
271→      }, 300);
272→    },
273→  }), [launchTerminal]);
274→
275→  useEffect(() => {
276→    if (!tab.repoPath || isLaunching) return;
277→
278→    const target = resolveAutoLaunchTarget(workspace);
279→    if (!target?.terminalTabId) return;
280→
281→    onWorkspaceChange((currentWorkspace) =>
282→      clearPaneAutoLaunch(currentWorkspace, target.terminalTabId!, target.paneId)
283→    );
284→    void launchTerminal("terminal", target);
285→  }, [tab.repoPath, workspace, isLaunching, launchTerminal, onWorkspaceChange]);
286→
287→  useEffect(() => {
288→    let cancelled = false;
289→    let unlisten: (() => void) | undefined;
290→
291→    getCurrentWindow()
292→      .onDragDropEvent((event) => {
293→        if (cancelled) return;
294→
295→        if (event.payload.type === "leave") {
296→          setIsDropTarget(false);
297→          return;
298→        }
299→
300→        const isInside = isPositionInsidePanel(event.payload.position);
301→        if (event.payload.type === "enter" || event.payload.type === "over") {
302→          setIsDropTarget(isInside);
303→          return;
304→        }
305→
306→        setIsDropTarget(false);
307→        if (!isInside) return;
308→        void sendDroppedImagePaths(event.payload.paths);
309→      })
310→      .then((cleanup) => {
311→        if (cancelled) {
312→          cleanup();
313→          return;
314→        }
315→        unlisten = cleanup;
316→      })
317→      .catch(console.error);
318→
319→    return () => {
320→      cancelled = true;
321→      setIsDropTarget(false);
322→      unlisten?.();
323→    };
324→  }, [isPositionInsidePanel, sendDroppedImagePaths]);
325→
326→  return (
327→    <div
328→      ref={panelRef}
329→      className="relative flex shrink-0 flex-col bg-[#0a0a0a]"
330→      style={{ height }}
331→    >
332→      <div className="flex items-center gap-2 border-t border-border bg-bg-raised px-3 py-1.5">
333→        <div className="flex min-w-0 flex-1 items-center gap-1 overflow-x-auto">
334→          {workspace.terminalTabs.map((terminalTab) => {
335→            const isActive = terminalTab.id === activeTerminalTab?.id;
336→            return (
337→              <div
338→                key={terminalTab.id}
339→                className={`flex items-center rounded-md border ${
340→                  isActive
341→                    ? "border-accent bg-accent-bg/40 text-accent-fg"
342→                    : "border-border-subtle text-fg-subtle"
343→                }`}
344→              >
345→                <button
346→                  onClick={() =>
347→                    onWorkspaceChange(
348→                      setActiveTerminalTabInWorkspace(workspace, terminalTab.id)
349→                    )
350→                  }
351→                  className="px-2.5 py-1 text-[11px]"
352→                >
353→                  {terminalTab.title}
354→                </button>
355→                <button
356→                  onClick={() => void closeTerminalTab(terminalTab.id)}
357→                  className="px-2 py-1 text-[11px] hover:text-red"
358→                  title="Close terminal tab"
359→                >
360→                  ✕
361→                </button>
362→              </div>
363→            );
364→          })}
365→          <button
366→            onClick={() => onWorkspaceChange(createTerminalTabInWorkspace(workspace))}
367→            className="rounded-md border border-border-subtle px-2.5 py-1 text-[11px] text-fg-subtle transition-colors hover:border-accent hover:text-accent-fg"
368→          >
369→            + Tab
370→          </button>
371→        </div>
372→
373→        <button
374→          onClick={() =>
375→            activeTerminalTab &&
376→            onWorkspaceChange(
377→              splitActivePaneInTerminalTab(workspace, activeTerminalTab.id, "vertical")
378→            )
379→          }
380→          disabled={!activeTerminalTab || activeTerminalTab.panes.length > 1}
381→          className="rounded-md border border-border-subtle px-2 py-1 text-[11px] text-fg-subtle transition-colors hover:border-accent hover:text-accent-fg disabled:opacity-50"
382→        >
383→          Split Vert
384→        </button>
385→        <button
386→          onClick={() =>
387→            activeTerminalTab &&
388→            onWorkspaceChange(
389→              splitActivePaneInTerminalTab(workspace, activeTerminalTab.id, "horizontal")
390→            )
391→          }
392→          disabled={!activeTerminalTab || activeTerminalTab.panes.length > 1}
393→          className="rounded-md border border-border-subtle px-2 py-1 text-[11px] text-fg-subtle transition-colors hover:border-accent hover:text-accent-fg disabled:opacity-50"
394→        >
395→          Split Horiz
396→        </button>
397→        <button
398→          onClick={onToggle}
399→          className="ml-auto px-2 py-1 text-[11px] text-fg-subtle hover:text-fg-muted"
400→        >
401→          ⌃` Toggle ▾
402→        </button>
403→      </div>
404→
405→      {error && (
406→        <div className="border-t border-border-subtle px-3 py-1 text-[11px] text-red">
407→          {error}
408→        </div>
409→      )}
410→
411→      <div className="flex-1 overflow-hidden">
412→        {activeTerminalTab ? (
413→          <div
414→            className={`flex h-full ${
415→              activeTerminalTab.splitDirection === "horizontal"
416→                ? "flex-col"
417→                : "flex-row"
418→            }`}
419→          >
420→            {activeTerminalTab.panes.map((pane, paneIndex) => {
421→              const isActive = pane.id === activeTerminalTab.activePaneId;
422→              const paneChrome = getPaneChrome(isActive);
423→              const paneMeta = pane.session
424→                ? isActive
425→                  ? "Live"
426→                  : "Attached"
427→                : pane.shouldAutoLaunch
428→                  ? "Starting"
429→                  : "Idle";
430→              const isSplit = activeTerminalTab.panes.length > 1;
431→              const paneFlexBasis = isSplit
432→                ? paneIndex === 0
433→                  ? `${activeTerminalTab.splitRatio * 100}%`
434→                  : `${(1 - activeTerminalTab.splitRatio) * 100}%`
435→                : undefined;
436→              return (
437→                <React.Fragment key={pane.id}>
438→                  {paneIndex === 1 && isSplit && (
439→                    <div
440→                      onMouseDown={(e) => {
441→                        e.preventDefault();
442→                        if (!activeTerminalTab) return;
443→                        const tabId = activeTerminalTab.id;
444→                        const isHorizontal = activeTerminalTab.splitDirection === "horizontal";
445→                        const container = e.currentTarget.parentElement;
446→                        if (!container) return;
447→                        const rect = container.getBoundingClientRect();
448→
449→                        function onMouseMove(ev: MouseEvent) {
450→                          const ratio = isHorizontal
451→                            ? (ev.clientY - rect.top) / rect.height
452→                            : (ev.clientX - rect.left) / rect.width;
453→                          onWorkspaceChange((currentWorkspace) =>
454→                            setSplitRatioInTerminalTab(currentWorkspace, tabId, ratio)
455→                          );
456→                        }
457→                        function onMouseUp() {
458→                          window.removeEventListener("mousemove", onMouseMove);
459→                          window.removeEventListener("mouseup", onMouseUp);
460→                        }
461→                        window.addEventListener("mousemove", onMouseMove);
462→                        window.addEventListener("mouseup", onMouseUp);
463→                      }}
464→                      className={`shrink-0 bg-border transition-colors hover:bg-accent ${
465→                        activeTerminalTab.splitDirection === "horizontal"
466→                          ? "h-[3px] cursor-row-resize"
467→                          : "w-[3px] cursor-col-resize"
468→                      }`}
469→                    />
470→                  )}
471→                  <div
472→                    onClick={() => focusPane(activeTerminalTab.id, pane.id)}
473→                    className={`flex min-h-0 min-w-0 flex-col ${
474→                      isActive ? "bg-bg-selected/30" : "bg-transparent"
475→                    }`}
476→                    style={isSplit ? { flexBasis: paneFlexBasis, flexGrow: 0, flexShrink: 0 } : { flex: 1 }}
477→                  >
478→                    <div className={paneChrome.rowClassName}>
479→                      <div className={paneChrome.buttonClassName}>
480→                        <span className={paneChrome.dotClassName} />
481→                        <span className={paneChrome.titleClassName}>
482→                          {pane.session?.label ?? "Terminal"}
483→                        </span>
484→                        <span className={paneChrome.metaClassName}>{paneMeta}</span>
485→                      </div>
486→                      {pane.session ? (
487→                        <button
488→                          onClick={(event) => {
489→                            event.stopPropagation();
490→                            void (async () => {
491→                              await killPaneSession(activeTerminalTab.id, pane.id);
492→                              if (activeTerminalTab.panes.length > 1) {
493→                                onWorkspaceChange((currentWorkspace) =>
494→                                  closePaneInTerminalTab(currentWorkspace, activeTerminalTab.id, pane.id)
495→                                );
496→                              } else {
497→                                onToggle();
498→                              }
499→                            })();
500→                          }}
501→                          className={paneChrome.closeClassName}
502→                          title="Kill session and close"
503→                        >
504→                          ✕
505→                        </button>
506→                      ) : (
507→                        <span className={paneChrome.metaClassName}>
508→                          {pane.shouldAutoLaunch ? "Starting terminal..." : "Terminal ready"}
509→                        </span>
510→                      )}
511→                    </div>
512→                    <div className="flex-1 overflow-hidden">
513→                      <GhosttyTerminal surfaceId={pane.session?.id ?? null} dialogOpen={dialogOpen} />
514→                    </div>
515→                  </div>
516→                </React.Fragment>
517→              );
518→            })}
519→          </div>
520→        ) : null}
521→      </div>
522→
523→      {isDropTarget && (
524→        <div className="pointer-events-none absolute inset-0 z-20 flex items-center justify-center border-2 border-dashed border-accent bg-accent-bg/55 px-4 text-center text-sm font-medium text-fg backdrop-blur-sm">
525→          Drop images to insert their file paths into the active terminal
526→        </div>
527→      )}
528→    </div>
529→  );
530→});
