  2→pub mod overlay;
  3→
  4→use objc2_app_kit::{NSPasteboard, NSPasteboardTypeString};
  5→use objc2_foundation::NSString;
  6→use std::ffi::{c_char, c_void, CString};
  7→use std::ops::{BitOr, BitOrAssign};
  8→use std::ptr;
  9→use std::sync::{Arc, Mutex};
