348→#[allow(dead_code)]
349→impl GhosttySurface {
350→    /// Create a new surface attached to the given NSView.
351→    pub fn new(
352→        app: &GhosttyApp,
353→        nsview: *mut c_void,
354→        working_dir: Option<&str>,
355→        command: Option<&str>,
356→        scale_factor: f64,
357→    ) -> Result<Self, String> {
358→        let working_dir_c = working_dir.map(|s| CString::new(s).unwrap());
359→        let command_c = command.map(|s| CString::new(s).unwrap());
360→
361→        let wd_ptr = working_dir_c.as_ref().map_or(ptr::null(), |s| s.as_ptr());
362→        let cmd_ptr = command_c.as_ref().map_or(ptr::null(), |s| s.as_ptr());
363→
364→        let mut config = unsafe { ghostty_surface_config_new() };
365→        config.platform_tag = GhosttyPlatform::MacOS;
366→        config.platform = GhosttyPlatformUnion { nsview };
367→        config.userdata = ptr::null_mut();
368→        config.scale_factor = scale_factor;
369→        config.font_size = 0.0; // 0 = use config default
370→        config.working_directory = wd_ptr;
371→        config.command = cmd_ptr;
372→        config.env_vars = ptr::null_mut();
373→        config.env_var_count = 0;
374→        config.initial_input = ptr::null();
375→        config.wait_after_command = false;
376→        config.context = GhosttySurfaceContext::Split;
377→
378→        // Debug: log config struct details
379→        {
380→            use std::io::Write;
381→            let ts = std::time::SystemTime::now()
382→                .duration_since(std::time::UNIX_EPOCH)
383→                .unwrap_or_default();
384→            let msg = format!(
385→                "[{}.{:03}] GhosttySurface::new config: app_ptr={:?}, nsview={:?}, \
386→                 scale_factor={}, font_size={}, working_dir_ptr={:?}, cmd_ptr={:?}, \
387→                 env_var_count={}, wait_after_command={}, context={:?}, \
388→                 struct size={}, struct align={}\n",
389→                ts.as_secs(),
390→                ts.subsec_millis(),
391→                app.raw(),
392→                nsview,
393→                scale_factor,
394→                config.font_size,
395→                config.working_directory,
396→                config.command,
397→                config.env_var_count,
398→                config.wait_after_command,
399→                config.context as u32,
400→                std::mem::size_of::<GhosttySurfaceConfig>(),
401→                std::mem::align_of::<GhosttySurfaceConfig>(),
402→            );
403→            if let Ok(mut f) = std::fs::OpenOptions::new()
404→                .create(true)
405→                .append(true)
406→                .open("/tmp/entire-terminal-debug.log")
407→            {
408→                let _ = f.write_all(msg.as_bytes());
409→            }
410→        }
411→
412→        let surface = unsafe { ghostty_surface_new(app.raw(), &config) };
413→        if surface.is_null() {
414→            return Err("ghostty_surface_new returned null".into());
415→        }
416→
417→        Ok(Self {
418→            inner: surface,
419→            _working_dir: working_dir_c,
420→            _command: command_c,
421→        })
422→    }
