542→pub(super) fn system_clipboard_text() -> Option<String> {
543→    let pasteboard = NSPasteboard::generalPasteboard();
544→    pasteboard
545→        .stringForType(unsafe { NSPasteboardTypeString })
546→        .map(|text| text.to_string())
547→}
548→
549→fn write_system_clipboard_text(text: &str) -> bool {
550→    let pasteboard = NSPasteboard::generalPasteboard();
551→    pasteboard.clearContents();
552→    let text = NSString::from_str(text);
553→    pasteboard.setString_forType(&text, unsafe { NSPasteboardTypeString })
554→}
