 1→/// Launch an agent in an external Ghostty window (for "Send to Agent" from review bar).
 2→pub fn launch_ghostty_agent(repo_path: &str, agent: &str, prompt: &str) -> Result<(), String> {
 3→    use std::process::Command;
 4→
 5→    let cli = match agent {
 6→        "claude-code" => "claude",
 7→        "codex" => "codex",
 8→        other => other,
 9→    };
10→
11→    // Write prompt to a temp file, then pipe it into the agent CLI
12→    let tmp = std::env::temp_dir().join(format!("entire-prompt-{}.txt", uuid_v4()));
13→    std::fs::write(&tmp, prompt).map_err(|e| format!("Failed to write prompt: {}", e))?;
14→
15→    let shell_cmd = format!(
16→        "cd {} && cat {} | {} ; rm -f {}",
17→        shell_escape(repo_path),
18→        shell_escape(&tmp.to_string_lossy()),
19→        cli,
20→        shell_escape(&tmp.to_string_lossy()),
21→    );
22→
23→    Command::new("ghostty")
24→        .args(["-e", "sh", "-c", &shell_cmd])
25→        .spawn()
26→        .map_err(|e| format!("Failed to launch ghostty: {}", e))?;
27→
28→    Ok(())
29→}
