324→impl GhosttyHostView {
325→    fn new(mtm: MainThreadMarker, frame: objc2_foundation::NSRect) -> Retained<Self> {
326→        let this = Self::alloc(mtm).set_ivars(GhosttyHostViewIvars::default());
327→        unsafe { msg_send![super(this), initWithFrame: frame] }
328→    }
329→
330→    fn surface(&self) -> *mut c_void {
331→        self.ivars().surface.load(Ordering::Relaxed)
332→    }
333→
334→    fn set_surface(&self, surface: *mut c_void) {
335→        self.ivars().surface.store(surface, Ordering::Relaxed);
336→    }
337→
338→    fn clear_surface(&self) {
339→        self.set_surface(ptr::null_mut());
340→    }
341→}
