118→#[tauri::command]
119→fn get_transcript(
120→    repo_path: String,
121→    checkpoint_id: String,
122→    session_index: u32,
123→) -> Result<Vec<session::TranscriptMessage>, String> {
124→    let repo = git::open_repo(&repo_path)?;
125→
126→    let prefix = &checkpoint_id[..2];
127→    let suffix = &checkpoint_id[2..];
128→    let meta_path = format!("{}/{}/metadata.json", prefix, suffix);
129→    let meta_content = read_blob(&repo, &meta_path).ok();
130→    let candidates =
131→        transcript_candidate_paths(&checkpoint_id, session_index, meta_content.as_deref());
132→
133→    for path in &candidates {
134→        if let Ok(content) = read_blob(&repo, path) {
135→            return Ok(session::read_transcript(&content));
136→        }
137→    }
138→
139→    Err(format!("Transcript not found for checkpoint {} session {}", checkpoint_id, session_index))
140→}
141→
142→fn transcript_candidate_paths(
143→    checkpoint_id: &str,
144→    session_index: u32,
145→    meta_content: Option<&str>,
146→) -> Vec<String> {
147→    let prefix = &checkpoint_id[..2];
148→    let suffix = &checkpoint_id[2..];
149→    let requested_session_dir = format!("{}/{}/{}", prefix, suffix, session_index);
150→    let mut candidates = Vec::new();
151→
152→    let mut push_candidate = |path: String| {
153→        if !path.is_empty() && !candidates.contains(&path) {
154→            candidates.push(path);
155→        }
156→    };
157→
158→    if let Some(meta_content) = meta_content {
159→        if let Ok(meta) = serde_json::from_str::<serde_json::Value>(meta_content) {
160→            if let Some(sessions) = meta.get("sessions").and_then(|s| s.as_array()) {
161→                let mut ordered_sessions = Vec::new();
162→                if let Some(session) = sessions.get(session_index as usize) {
163→                    ordered_sessions.push(session);
164→                }
165→                for (idx, session) in sessions.iter().enumerate() {
166→                    if idx != session_index as usize {
167→                        ordered_sessions.push(session);
168→                    }
169→                }
170→
171→                for session in ordered_sessions {
172→                    if let Some(path) = session.get("transcript").and_then(|p| p.as_str()) {
173→                        push_candidate(path.trim_start_matches('/').to_string());
174→                    }
175→                }
176→            }
177→        }
178→    }
179→
180→    push_candidate(format!("{}/full.jsonl", requested_session_dir));
181→    push_candidate(format!("{}/transcript.jsonl", requested_session_dir));
182→    candidates
183→}
