811→                    let state = handle.state::<Mutex<ghostty::GhosttyState>>();
812→                    let mutex = state.inner();
813→                    if let Ok(gs) = mutex.lock() {
814→                        if let Some(app) = gs.app.as_ref() {
815→                            app.tick();
816→                        }
817→                    }
818→                });
819→
820→                let _tick_timer = unsafe {
821→                    NSTimer::scheduledTimerWithTimeInterval_repeats_block(
822→                        1.0 / 60.0,
823→                        true,
