343→/// Manages a native NSView overlay positioned on top of the Tauri webview.
344→/// Ghostty renders into this view via its own Metal infrastructure.
345→pub struct GhosttyOverlay {
346→    /// The NSView that contains the Metal layer. libghostty renders into this.
347→    view: Retained<GhosttyHostView>,
348→    /// Track visibility so we avoid redundant show/hide calls.
349→    visible: bool,
350→}
351→
352→// SAFETY: NSView operations are dispatched on the main thread via objc2.
353→// The overlay is only mutated through Mutex<GhosttyState>.
354→unsafe impl Send for GhosttyOverlay {}
355→unsafe impl Sync for GhosttyOverlay {}
356→
357→impl GhosttyOverlay {
358→    /// Create a new overlay NSView and add it as a subview of the given window.
359→    ///
360→    /// # Safety
361→    /// Must be called on the main thread. `window` must be a valid NSWindow pointer.
362→    pub unsafe fn new(window: *mut c_void) -> Result<Self, String> {
363→        // We must be on the main thread to create NSView
364→        let mtm = MainThreadMarker::new()
365→            .ok_or_else(|| "Must be called on the main thread".to_string())?;
366→
367→        let window: &NSWindow = unsafe { &*(window as *const NSWindow) };
368→        let content_view = window
369→            .contentView()
370→            .ok_or_else(|| "Window has no contentView".to_string())?;
371→
372→        // Create the overlay NSView
373→        let frame = content_view.frame();
374→        let view = GhosttyHostView::new(mtm, frame);
375→
376→        // Enable layer-backing (required for ghostty's Metal rendering)
377→        // but do NOT pre-create a CAMetalLayer — ghostty sets up its own
378→        // rendering infrastructure on the view internally.
379→        view.setWantsLayer(true);
380→
381→        // Add as subview — on top of the webview content
382→        content_view.addSubview(&view);
383→
384→        // Start hidden until explicitly shown
385→        view.setHidden(true);
386→
387→        Ok(Self {
388→            view,
389→            visible: false,
390→        })
391→    }
392→
393→    /// Returns the raw NSView pointer for passing to libghostty's surface config.
394→    pub fn nsview_ptr(&self) -> *mut c_void {
395→        let view_ref: &NSView = &self.view;
396→        view_ref as *const NSView as *mut c_void
397→    }
398→
399→    pub fn set_surface(&self, surface: *mut c_void) {
400→        self.view.set_surface(surface);
401→    }
402→
403→    pub fn clear_surface(&self) {
404→        self.view.clear_surface();
405→    }
406→
407→    /// Reposition and resize the overlay to match the terminal panel in the webview.
408→    ///
409→    /// Coordinates come from the frontend (top-left origin, CSS pixels).
410→    /// macOS NSView uses bottom-left origin, so we flip Y.
411→    pub fn update_frame(&self, x: f64, y: f64, width: f64, height: f64) {
412→        if let Some(superview) = unsafe { self.view.superview() } {
413→            let parent_height = superview.frame().size.height;
414→            // Convert from top-left (web) to bottom-left (macOS) origin
415→            let flipped_y = parent_height - y - height;
416→
417→            let frame = objc2_foundation::NSRect::new(
418→                objc2_foundation::NSPoint::new(x, flipped_y),
419→                objc2_foundation::NSSize::new(width, height),
420→            );
421→            self.view.setFrame(frame);
422→        }
423→    }
424→
425→    /// Show or hide the overlay.
426→    pub fn set_visible(&mut self, visible: bool) {
427→        if self.visible != visible {
428→            self.view.setHidden(!visible);
429→            self.visible = visible;
430→        }
431→    }
432→
433→    /// Whether the overlay is currently visible.
434→    #[allow(dead_code)]
435→    pub fn is_visible(&self) -> bool {
436→        self.visible
437→    }
438→
439→    /// Make the overlay the first responder (receive keyboard input).
440→    pub fn focus(&self) -> bool {
441→        unsafe {
442→            if let Some(window) = self.view.window() {
443→                let result: bool = msg_send![&*window, makeFirstResponder: &*self.view];
444→                return result;
445→            }
446→        }
447→        false
448→    }
449→}
450→
451→impl Drop for GhosttyOverlay {
452→    fn drop(&mut self) {
453→        // Remove from superview to clean up
454→        self.view.removeFromSuperview();
455→    }
456→}
457→
458→/// Get the raw NSWindow pointer from a Tauri webview window.
459→pub fn get_nswindow(window: &tauri::WebviewWindow) -> Result<*mut c_void, String> {
460→    #[cfg(target_os = "macos")]
461→    {
462→        use raw_window_handle::{HasWindowHandle, RawWindowHandle};
463→
464→        let handle = window
465→            .window_handle()
466→            .map_err(|e| format!("Failed to get window handle: {}", e))?;
467→
468→        match handle.as_raw() {
469→            RawWindowHandle::AppKit(handle) => {
470→                // ns_view is the content view — we need the window.
471→                // Get the window from the view.
472→                let ns_view = handle.ns_view.as_ptr() as *mut c_void;
473→                let ns_window: *mut c_void =
474→                    unsafe { msg_send![ns_view as *mut AnyObject, window] };
475→                Ok(ns_window)
476→            }
477→            _ => Err("Expected AppKit window handle on macOS".into()),
478→        }
479→    }
480→
481→    #[cfg(not(target_os = "macos"))]
482→    {
483→        let _ = window;
484→        Err("NSView overlay is only supported on macOS".into())
485→    }
486→}
